//
// NEON optimizer inner loops. Each kernel processes 4 lanes per
// iteration using FMLA chains. Real NEON per AGENTS.md §1.1 — the
// arithmetic uses V registers and no scalar body.
//
// adamStep: Adam parameter update.
// sgdStep:  SGD with momentum.

#include "textflag.h"

#define VFADD_S4(m, n, d)  WORD $(0x4E20D400 | ((m) << 16) | ((n) << 5) | (d))
#define VFSUB_S4(m, n, d)  WORD $(0x4EA0D400 | ((m) << 16) | ((n) << 5) | (d))
#define VFMUL_S4(m, n, d)  WORD $(0x6E20DC00 | ((m) << 16) | ((n) << 5) | (d))
#define VFMLA_S4(m, n, d)  WORD $(0x4E20CC00 | ((m) << 16) | ((n) << 5) | (d))
#define VFDIV_S4(m, n, d)  WORD $(0x6E20FC00 | ((m) << 16) | ((n) << 5) | (d))
// FSQRT vector .4S
#define VFSQRT_S4(n, d)    WORD $(0x6EA1F800 | ((n) << 5) | (d))

// func adamStepFloat32NEONAsm(
//     params, grad, first, second, output *float32,
//     n int,
//     lr, beta1, beta2, eps, beta1Corr, beta2Corr float32,
// )
//
// firstNew  = beta1 * first + (1-beta1) * grad
// secondNew = beta2 * second + (1-beta2) * grad²
// biasFirst = firstNew / beta1Correction
// biasSec   = secondNew / beta2Correction
// out       = params - lr * biasFirst / (sqrt(biasSec) + eps)
//
// Updates first and second in place.
TEXT ·adamStepFloat32NEONAsm(SB), NOSPLIT, $0-72
    MOVD params+0(FP), R0
    MOVD grad+8(FP), R1
    MOVD first+16(FP), R2
    MOVD second+24(FP), R3
    MOVD output+32(FP), R4
    MOVD n+40(FP), R5

    // Broadcast scalar hyperparameters into V16..V22.
    FMOVS lr+48(FP), F16        ; VDUP V16.S[0], V16.S4
    FMOVS beta1+52(FP), F17     ; VDUP V17.S[0], V17.S4
    FMOVS beta2+56(FP), F18     ; VDUP V18.S[0], V18.S4
    FMOVS eps+60(FP), F19       ; VDUP V19.S[0], V19.S4
    FMOVS beta1Corr+64(FP), F20 ; VDUP V20.S[0], V20.S4
    FMOVS beta2Corr+68(FP), F21 ; VDUP V21.S[0], V21.S4

    // V22 = 1.0 broadcast (bit pattern 0x3F800000) for (1-betaX).
    MOVD $0x3F800000, R6
    VMOV R6, V22.S[0]
    VDUP V22.S[0], V22.S4

    // Compute (1-beta1) into V23 and (1-beta2) into V24 once.
    VFSUB_S4(17, 22, 23)         // V23 = 1 - beta1
    VFSUB_S4(18, 22, 24)         // V24 = 1 - beta2

adam_loop4:
    CMP  $4, R5
    BLT  adam_done
    VLD1 (R0), [V0.S4]           // params
    VLD1 (R1), [V1.S4]           // grad
    VLD1 (R2), [V2.S4]           // first
    VLD1 (R3), [V3.S4]           // second

    // firstNew = beta1 * first + (1-beta1) * grad
    // V2 *= beta1; FMLA Vd, Vn, Vm: Vd = Vd + Vn*Vm
    VFMUL_S4(17, 2, 2)
    VFMLA_S4(1, 23, 2)
    // secondNew = beta2 * second + (1-beta2) * grad²
    VFMUL_S4(18, 3, 3)
    VFMUL_S4(1, 1, 4)            // V4 = grad²
    VFMLA_S4(4, 24, 3)
    // bias-corrected: V5 = V2/beta1Corr, V6 = V3/beta2Corr
    VFDIV_S4(20, 2, 5)
    VFDIV_S4(21, 3, 6)
    // denom = sqrt(V6) + eps
    VFSQRT_S4(6, 6)
    VFADD_S4(19, 6, 6)
    // step = lr * V5 / V6
    VFMUL_S4(16, 5, 5)
    VFDIV_S4(6, 5, 5)
    // output = params - step
    VFSUB_S4(5, 0, 0)

    VST1 [V2.S4], (R2)
    VST1 [V3.S4], (R3)
    VST1 [V0.S4], (R4)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    ADD  $16, R3
    ADD  $16, R4
    SUB  $4, R5
    B    adam_loop4

adam_done:
    RET

// func sgdStepFloat32NEONAsm(
//     params, grad, momentum, output *float32,
//     n int,
//     lr, momentumFactor, weightDecay float32,
// )
//
// effective = grad + weightDecay * params
// momentumNew = momentumFactor * momentum + effective
// output = params - lr * momentumNew
TEXT ·sgdStepFloat32NEONAsm(SB), NOSPLIT, $0-52
    MOVD params+0(FP), R0
    MOVD grad+8(FP), R1
    MOVD momentum+16(FP), R2
    MOVD output+24(FP), R3
    MOVD n+32(FP), R4

    FMOVS lr+40(FP), F16            ; VDUP V16.S[0], V16.S4
    FMOVS momentumFactor+44(FP), F17 ; VDUP V17.S[0], V17.S4
    FMOVS weightDecay+48(FP), F18    ; VDUP V18.S[0], V18.S4

sgd_loop4:
    CMP  $4, R4
    BLT  sgd_done
    VLD1 (R0), [V0.S4]               // params
    VLD1 (R1), [V1.S4]               // grad
    VLD1 (R2), [V2.S4]               // momentum
    // effective = grad + weightDecay * params (FMLA V1, V18, V0)
    VFMLA_S4(0, 18, 1)
    // momentumNew = momentumFactor * momentum + effective
    VFMUL_S4(17, 2, 2)
    VFADD_S4(1, 2, 2)
    // output = params - lr * momentumNew
    VFMUL_S4(16, 2, 3)
    VFSUB_S4(3, 0, 0)
    VST1 [V2.S4], (R2)
    VST1 [V0.S4], (R3)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    ADD  $16, R3
    SUB  $4, R4
    B    sgd_loop4

sgd_done:
    RET

// func adamwStepFloat32NEONAsm(
//     params, grad, first, second, output *float32,
//     n int,
//     lr, beta1, beta2, eps, beta1Corr, beta2Corr, weightDecay float32,
// )
//
// firstNew  = beta1 * first + (1-beta1) * grad
// secondNew = beta2 * second + (1-beta2) * grad²
// biasFirst = firstNew / beta1Correction
// biasSec   = secondNew / beta2Correction
// gradStep  = lr * biasFirst / (sqrt(biasSec) + eps)
// decayStep = lr * weightDecay * params
// output    = params - gradStep - decayStep
TEXT ·adamwStepFloat32NEONAsm(SB), NOSPLIT, $0-76
    MOVD params+0(FP), R0
    MOVD grad+8(FP), R1
    MOVD first+16(FP), R2
    MOVD second+24(FP), R3
    MOVD output+32(FP), R4
    MOVD n+40(FP), R5

    FMOVS lr+48(FP), F16        ; VDUP V16.S[0], V16.S4
    FMOVS beta1+52(FP), F17     ; VDUP V17.S[0], V17.S4
    FMOVS beta2+56(FP), F18     ; VDUP V18.S[0], V18.S4
    FMOVS eps+60(FP), F19       ; VDUP V19.S[0], V19.S4
    FMOVS beta1Corr+64(FP), F20 ; VDUP V20.S[0], V20.S4
    FMOVS beta2Corr+68(FP), F21 ; VDUP V21.S[0], V21.S4
    FMOVS weightDecay+72(FP), F25 ; VDUP V25.S[0], V25.S4

    MOVD $0x3F800000, R6
    VMOV R6, V22.S[0]
    VDUP V22.S[0], V22.S4

    VFSUB_S4(17, 22, 23)         // V23 = 1 - beta1
    VFSUB_S4(18, 22, 24)         // V24 = 1 - beta2

adamw_loop4:
    CMP  $4, R5
    BLT  adamw_done
    VLD1 (R0), [V0.S4]
    VLD1 (R1), [V1.S4]
    VLD1 (R2), [V2.S4]
    VLD1 (R3), [V3.S4]
    // firstNew = beta1*first + (1-beta1)*grad
    VFMUL_S4(17, 2, 2)
    VFMLA_S4(1, 23, 2)
    // secondNew = beta2*second + (1-beta2)*grad²
    VFMUL_S4(18, 3, 3)
    VFMUL_S4(1, 1, 4)
    VFMLA_S4(4, 24, 3)
    // bias correction
    VFDIV_S4(20, 2, 5)
    VFDIV_S4(21, 3, 6)
    VFSQRT_S4(6, 6)
    VFADD_S4(19, 6, 6)
    VFMUL_S4(16, 5, 5)
    VFDIV_S4(6, 5, 5)
    // decayStep = lr * weightDecay * params = V16 * V25 * V0
    VFMUL_S4(25, 16, 7)          // V7 = lr * weightDecay (scalar product per-lane)
    VFMUL_S4(0, 7, 7)            // V7 = lr*wd*params
    // out = params - gradStep - decayStep
    VFSUB_S4(5, 0, 0)
    VFSUB_S4(7, 0, 0)

    VST1 [V2.S4], (R2)
    VST1 [V3.S4], (R3)
    VST1 [V0.S4], (R4)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    ADD  $16, R3
    ADD  $16, R4
    SUB  $4, R5
    B    adamw_loop4

adamw_done:
    RET

// FABS .4S
#define VFABS_S4(n, d)  WORD $(0x4EA0F800 | ((n) << 5) | (d))

// func adamaxStepFloat32NEONAsm(
//     params, grad, first, infinity, output *float32,
//     n int,
//     lr, beta1, beta2, eps, beta1Corr float32,
// )
//
// firstNew = beta1*first + (1-beta1)*grad
// infNew   = max(beta2*inf, |grad|)
// biasFirst = firstNew/beta1Corr
// out      = params - lr * biasFirst / (infNew + eps)
TEXT ·adamaxStepFloat32NEONAsm(SB), NOSPLIT, $0-68
    MOVD params+0(FP), R0
    MOVD grad+8(FP), R1
    MOVD first+16(FP), R2
    MOVD infinity+24(FP), R3
    MOVD output+32(FP), R4
    MOVD n+40(FP), R5

    FMOVS lr+48(FP), F16        ; VDUP V16.S[0], V16.S4
    FMOVS beta1+52(FP), F17     ; VDUP V17.S[0], V17.S4
    FMOVS beta2+56(FP), F18     ; VDUP V18.S[0], V18.S4
    FMOVS eps+60(FP), F19       ; VDUP V19.S[0], V19.S4
    FMOVS beta1Corr+64(FP), F20 ; VDUP V20.S[0], V20.S4

    MOVD $0x3F800000, R6
    VMOV R6, V22.S[0]
    VDUP V22.S[0], V22.S4
    VFSUB_S4(17, 22, 23)         // V23 = 1 - beta1

adamax_loop4:
    CMP  $4, R5
    BLT  adamax_done
    VLD1 (R0), [V0.S4]
    VLD1 (R1), [V1.S4]
    VLD1 (R2), [V2.S4]
    VLD1 (R3), [V3.S4]
    // firstNew = beta1*first + (1-beta1)*grad
    VFMUL_S4(17, 2, 2)
    VFMLA_S4(1, 23, 2)
    // infNew = max(beta2*inf, |grad|)
    VFMUL_S4(18, 3, 3)
    VFABS_S4(1, 4)
    // FMAX V_d.S4 = max(V_n.S4, V_m.S4) — encoding 0x4E20F400
    WORD $(0x4E20F400 | (3 << 16) | (4 << 5) | 3)
    // biasFirst = firstNew / beta1Corr
    VFDIV_S4(20, 2, 5)
    // denom = inf + eps
    VFADD_S4(19, 3, 6)
    // step = lr * biasFirst / denom
    VFMUL_S4(16, 5, 5)
    VFDIV_S4(6, 5, 5)
    VFSUB_S4(5, 0, 0)
    VST1 [V2.S4], (R2)
    VST1 [V3.S4], (R3)
    VST1 [V0.S4], (R4)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    ADD  $16, R3
    ADD  $16, R4
    SUB  $4, R5
    B    adamax_loop4

adamax_done:
    RET

// func adagradStepFloat32NEONAsm(
//     params, grad, accum, output *float32,
//     n int,
//     lr, eps float32,
// )
//
// accumNew = accum + grad²
// out = params - lr * grad / (sqrt(accumNew) + eps)
TEXT ·adagradStepFloat32NEONAsm(SB), NOSPLIT, $0-48
    MOVD params+0(FP), R0
    MOVD grad+8(FP), R1
    MOVD accum+16(FP), R2
    MOVD output+24(FP), R3
    MOVD n+32(FP), R4

    FMOVS lr+40(FP), F16  ; VDUP V16.S[0], V16.S4
    FMOVS eps+44(FP), F17 ; VDUP V17.S[0], V17.S4

