    CMP  $4, R4
    BLT  ag_done
    VLD1 (R0), [V0.S4]
    VLD1 (R1), [V1.S4]
    VLD1 (R2), [V2.S4]
    // accumNew = accum + grad²
    VFMLA_S4(1, 1, 2)          // V2 += V1*V1
    // denom = sqrt(accumNew) + eps
    VFSQRT_S4(2, 3)
    VFADD_S4(17, 3, 3)
    // step = lr * grad / denom
    VFMUL_S4(16, 1, 4)
    VFDIV_S4(3, 4, 4)
    VFSUB_S4(4, 0, 0)
    VST1 [V2.S4], (R2)
    VST1 [V0.S4], (R3)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    ADD  $16, R3
    SUB  $4, R4
    B    ag_loop4

ag_done:
    RET

// func rmspropStepFloat32NEONAsm(
//     params, grad, second, output *float32,
//     n int,
//     lr, decay, eps float32,
// )
//
// secondNew = decay*second + (1-decay)*grad²
// out = params - lr * grad / (sqrt(secondNew) + eps)
TEXT ·rmspropStepFloat32NEONAsm(SB), NOSPLIT, $0-52
    MOVD params+0(FP), R0
    MOVD grad+8(FP), R1
    MOVD second+16(FP), R2
    MOVD output+24(FP), R3
    MOVD n+32(FP), R4

