    CMP  $4, R4
    BLT  rms_done
    VLD1 (R0), [V0.S4]
    VLD1 (R1), [V1.S4]
    VLD1 (R2), [V2.S4]
    // secondNew = decay*second + (1-decay)*grad²
    VFMUL_S4(17, 2, 2)
    VFMUL_S4(1, 1, 4)
    VFMLA_S4(4, 23, 2)
    // denom = sqrt(V2) + eps
    VFSQRT_S4(2, 5)
    VFADD_S4(18, 5, 5)
    // step = lr * grad / denom
    VFMUL_S4(16, 1, 4)
    VFDIV_S4(5, 4, 4)
    VFSUB_S4(4, 0, 0)
    VST1 [V2.S4], (R2)
    VST1 [V0.S4], (R3)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    ADD  $16, R3
    SUB  $4, R4
    B    rms_loop4

rms_done:
    RET
